"use client";

import {
  createContext,
  createElement,
  useContext,
  type ReactNode,
} from "react";
import type {
  WalletEip712Payload,
  WalletTxPayload,
} from "@aomi-labs/react";
import {
  AOMI_AUTH_BOOTING_IDENTITY,
  type AomiAuthIdentity,
} from "./auth-identity";

// =============================================================================
// WalletAdapter type
// =============================================================================

export type AomiAuthAdapter = {
  identity: AomiAuthIdentity;
  isReady: boolean;
  isSwitchingChain: boolean;
  canConnect: boolean;
  canManageAccount: boolean;
  connect: () => Promise<void>;
  disconnect: () => Promise<void>;
  manageAccount: () => Promise<void>;
  switchChain?: (chainId: number) => Promise<void>;
  sendTransaction?: (
    payload: WalletTxPayload,
  ) => Promise<{ txHash: string; amount?: string }>;
  signTypedData?: (
    payload: WalletEip712Payload,
  ) => Promise<{ signature: string }>;
};


// =============================================================================
// Disconnected default
// =============================================================================

export const AOMI_AUTH_DISCONNECTED_ADAPTER: AomiAuthAdapter = {
  identity: {
    status: "disconnected",
    isConnected: false,
    address: undefined,
    chainId: undefined,
    authProvider: undefined,
    primaryLabel: "Not connected",
    secondaryLabel: undefined,
  },
  isReady: true,
  isSwitchingChain: false,
  canConnect: false,
  canManageAccount: false,
  connect: async () => undefined,
  disconnect: async () => undefined,
  manageAccount: async () => undefined,
};

export const AOMI_AUTH_BOOTING_ADAPTER: AomiAuthAdapter = {
  identity: AOMI_AUTH_BOOTING_IDENTITY,
  isReady: false,
  isSwitchingChain: false,
  canConnect: false,
  canManageAccount: false,
  connect: async () => undefined,
  disconnect: async () => undefined,
  manageAccount: async () => undefined,
};

// =============================================================================
// Context
// =============================================================================

export const AomiAuthAdapterContext =
  createContext<AomiAuthAdapter | undefined>(undefined);

export function AomiAuthAdapterProvider({
  children,
  value,
}: {
  children: ReactNode;
  value?: AomiAuthAdapter;
}) {
  const inheritedAdapter = useContext(AomiAuthAdapterContext);

  return createElement(
    AomiAuthAdapterContext.Provider,
    { value: value ?? inheritedAdapter },
    children,
  );
}

// =============================================================================
// Hook
// =============================================================================

export function useAomiAuthAdapter(): AomiAuthAdapter {
  const contextAdapter = useContext(AomiAuthAdapterContext);

  return contextAdapter ?? AOMI_AUTH_BOOTING_ADAPTER;
}

"use client";

import { useAomiAuthAdapter } from "./aomi-auth-adapter";

export type AomiAuthStatus = "booting" | "disconnected" | "connected";

export type AomiAuthIdentity = {
  status: AomiAuthStatus;
  isConnected: boolean;
  address?: string;
  chainId?: number;
  authProvider?: string;
  primaryLabel: string;
  secondaryLabel?: string;
};

export const AOMI_AUTH_DISCONNECTED_IDENTITY: AomiAuthIdentity = {
  status: "disconnected",
  isConnected: false,
  address: undefined,
  chainId: undefined,
  authProvider: undefined,
  primaryLabel: "Not connected",
  secondaryLabel: undefined,
};

export const AOMI_AUTH_BOOTING_IDENTITY: AomiAuthIdentity = {
  status: "booting",
  isConnected: false,
  address: undefined,
  chainId: undefined,
  authProvider: undefined,
  primaryLabel: "Loading Wallet...",
  secondaryLabel: undefined,
};

export function formatAddress(address?: string): string | undefined {
  if (!address) return undefined;
  return `${address.slice(0, 5)}..${address.slice(-2)}`;
}

export function formatAuthProvider(provider?: string): string | undefined {
  if (!provider) return undefined;

  const labelMap: Record<string, string> = {
    google: "Google",
    github: "GitHub",
    apple: "Apple",
    facebook: "Facebook",
    x: "X",
    discord: "Discord",
    farcaster: "Farcaster",
    telegram: "Telegram",
    email: "Email",
    phone: "Phone",
    wallet: "Wallet",
  };

  return labelMap[provider] ?? provider;
}

export function inferAuthProvider(authMethods: unknown): string | undefined {
  if (!(authMethods instanceof Set) || authMethods.size === 0) return undefined;

  const allowed = new Set([
    "google",
    "github",
    "apple",
    "facebook",
    "x",
    "discord",
    "farcaster",
    "telegram",
    "email",
    "phone",
  ]);

  for (const method of authMethods) {
    if (typeof method !== "string") continue;
    const normalized = method.toLowerCase();
    if (allowed.has(normalized)) return normalized;
  }

  const first = authMethods.values().next().value;
  return typeof first === "string" ? first.toLowerCase() : undefined;
}

export function useAomiAuthIdentity(): AomiAuthIdentity {
  return useAomiAuthAdapter().identity;
}
